CREATE TABLE students (student_id INTEGER PRIMARY KEY, first_name TEXT NOT NULL, last_name TEXT NOT NULL, email TEXT UNIQUE NOT NULL, degree_program TEXT NOT NULL, gpa REAL NOT NULL CHECK (gpa BETWEEN 2.0 AND 4.0));
CREATE TABLE companies (company_id INTEGER PRIMARY KEY, company_name TEXT NOT NULL, contact_email TEXT UNIQUE NOT NULL, location TEXT NOT NULL, verified TEXT NOT NULL CHECK (verified IN ('Y','N')));
CREATE TABLE job_postings (posting_id INTEGER PRIMARY KEY, company_id INTEGER NOT NULL REFERENCES companies(company_id), title TEXT NOT NULL, posting_type TEXT NOT NULL CHECK (posting_type IN ('J','I')), requirements TEXT, closing_date TEXT NOT NULL);
CREATE TABLE applications (application_id INTEGER PRIMARY KEY, student_id INTEGER NOT NULL REFERENCES students(student_id), posting_id INTEGER NOT NULL REFERENCES job_postings(posting_id), application_date TEXT NOT NULL, status TEXT NOT NULL CHECK (status IN ('Applied','Shortlisted','Rejected','Withdrawn')), UNIQUE(student_id, posting_id));
CREATE TABLE interviews (interview_id INTEGER PRIMARY KEY, application_id INTEGER NOT NULL REFERENCES applications(application_id), interview_date TEXT NOT NULL, interview_time TEXT NOT NULL, outcome TEXT NOT NULL CHECK (outcome IN ('Passed','Failed','Pending','Cancelled')));
CREATE TABLE offers (offer_id INTEGER PRIMARY KEY, interview_id INTEGER NOT NULL UNIQUE REFERENCES interviews(interview_id), offer_date TEXT NOT NULL, start_date TEXT, salary REAL CHECK (salary IS NULL OR salary >= 0), accepted TEXT NOT NULL CHECK (accepted IN ('Y','N')));
